UPDATE tb_community_post
SET view_count = view_count + 1
WHERE id = #{postId}

UPDATE tb_community_post
SET comment_count = comment_count + 1
WHERE id = #{postId}

mapper.select:
SELECT p.id, p.user_id AS userId, u.username, u.user_avatar AS userAvatar, p.title, CAST(p.content AS CHAR) AS content, p.category, p.tags, p.cover_url AS coverUrl, p.view_count AS viewCount, p.like_count AS likeCount, p.comment_count AS commentCount, p.favorite_count AS favoriteCount, p.is_top AS isTop, p.is_hot AS isHot, p.status, p.create_time AS createTime, p.update_time AS updateTime, 0 AS isLiked, 0 AS isFavorited FROM tb_community_post p LEFT JOIN tb_user u ON p.user_id = u.id
AND p.status = #{status}
AND p.category = #{category}
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%'))
AND p.tags LIKE CONCAT('%', #{tag}, '%')
AND p.user_id = #{userId}
ORDER BY p.is_top DESC, p.create_time DESC
